   272→	private async saveStyleToDatabase({
   273→		style,
   274→		allCategories,
   275→		isProductActive,
   276→	}: {
   277→		style: MMSStyleToProcess;
   278→		allCategories: MMSAllStyleCategory[];
   279→		isProductActive: boolean;
   280→	}): Promise<void> {
   281→		try {
   282→			const categoryIds = this.extractCategoryIds({ style });
   283→			const categoriesWithParentsIds = this.extractCategoriesWithParents({
   284→				categoryIds,
   285→				allCategories,
   286→			});
   287→
   288→			const purchasesCount =
   289→				await this.productAnnualSalesService.getPurchasesCountForLatestYear({
   290→					styleId: Number(style.id),
   291→				});
   292→
   293→			const styleData = {
   294→				style_id: style.id,
   295→				primary_category_id: style.primary_category_id ?? 0,
   296→				root_category_id: this.getRootCategoryId({ style, allCategories }),
   297→				purchases_count: purchasesCount,
   298→				categories_ids: categoryIds,
   299→				categories_with_parents_ids: categoriesWithParentsIds,
   300→				is_active: isProductActive,
   301→				name: style.name,
   302→				decoration_method: style.decoration_method,
   303→				features: style.features,
   304→				general_comments: style.general_comments,
   305→				manufacturer: style.manufacturer,
   306→				minimum_quantity: style.min_qty,
   307→				rating_count: style.rating_count,
   308→				rating_score: Number(style.rating_score),
   309→				sizes: (style.style_sizes ?? []).map((size) => size.name),
   310→				style_type: style.style_type,
   311→				price_level: style.price_level,
   312→				primary_category_name: style.primary_category?.name ?? '',
   313→				default_quote_qty: style.primary_category?.default_quote_qty ?? 1,
   314→				product_type: style.product_type,
   315→				style_card_image_url: this.generateStyleCardImageUrl({
   316→					styleId: style.id,
   317→					catalogDetailImageMd5: style.catalog_detail_image_md5,
   318→				}),
   319→				broad_category_names: this.getBroadCategoryNames({
   320→					categories: style.categories,
   321→					allCategories,
   322→				}),
   323→				sub_category_names: this.getStylesSubcategories({
   324→					categories: style.categories,
   325→					allCategories,
   326→				}),
   327→				turn_time: style.turntime ? Number(style.turntime.standard) : 0,
   328→				rush_turn_time: style.turntime ? Number(style.turntime.rush) : 0,
   329→				no_minimum: style.has_singles_enabled_colors,
   330→				link_path: this.calculateLink({ style, allCategories })?.path ?? '',
   331→				brand: this.getBrand([style.brand]),
   332→				min_qty: style.min_qty,
   333→			};
   334→
   335→			if (!style.colors?.length) {
   336→				this.logger.debug(`Style ${style.id} has no colors to save`);
   337→				return;
   338→			}
   339→
   340→			const colors = style.colors.map((color) => {
   341→				const isActive = color.status === styleStatus.ACTIVE;
   342→				const hasRgb = Array.isArray(color.rbgs) && color.rbgs[0];
   343→				const colorRgb =
   344→					hasRgb && color.rbgs[0] ? convertRGBToString(color.rbgs[0]) : null;
   345→
   346→				return {
   347→					color_id: color.id,
   348→					color_rgb: colorRgb,
   349→					color_name: color.name,
   350→					is_active: Boolean(isActive && hasRgb),
   351→					image_url: color.image_url,
   352→				};
   353→			});
   354→
   355→			const defaultUnitPrices = this.getDefaultUnitPrices({ style }).map((priceData) => ({
   356→				quantity: priceData.quantity,
   357→				price: Number(priceData.price),
   358→				regular_unit_price: priceData.regular_unit_price
   359→					? Number(priceData.regular_unit_price)
   360→					: null,
   361→				algorithm: priceData.algorithm,
   362→			}));
   363→
   364→			await this.stylesService.saveCompleteStyle({
   365→				styleData,
   366→				colors,
   367→				defaultUnitPrices,
   368→			});
   369→
   370→			this.logger.debug(`Successfully saved style ${style.id} to database`);
   371→		} catch (error: unknown) {
   372→			const err = error instanceof Error ? error : new Error(String(error));
   373→			this.logger.error(`Failed to save style ${style.id} to database: ${err.message}`);
   374→			throw err;
   375→		}
   376→	}
