   378→	private async generateLLMFeatures({
   379→		style,
   380→		featuresRelatedFields,
   381→	}: {
   382→		style: MMSStyleToProcess;
   383→		featuresRelatedFields: FeaturesRelatedFields;
   384→	}): Promise<string[]> {
   385→		try {
   386→			const result = await withRetry({
   387→				fn: () => this.OpenAIService.generateProductFeatures({ productInfo: style }),
   388→				options: { retryCount: 2 },
   389→			});
   390→
   391→			if (result.error) {
   392→				this.logger.error(
   393→					`Failed to generate features for style ${style.id}: ${result.error}`,
   394→				);
   395→				throw new Error(`Failed to generate features: ${result.error}`);
   396→			}
   397→
   398→			return result.description ?? [];
   399→		} catch (error) {
   400→			const errorMessage = error instanceof Error ? error.message : String(error);
   401→			const isTokenLimitError = errorMessage.includes('maximum context length');
   402→
   403→			if (isTokenLimitError) {
   404→				this.logger.warn(
   405→					`Token limit exceeded for style ${style.id}, retrying with reduced fields`,
   406→				);
   407→
   408→				const reducedResult = await withRetry({
   409→					fn: () =>
   410→						this.OpenAIService.generateProductFeatures({
   411→							productInfo: featuresRelatedFields as unknown as MMSStyleToProcess,
   412→						}),
   413→					options: { retryCount: 2 },
   414→				});
   415→
   416→				if (reducedResult.error) {
   417→					throw new Error(`Failed to generate features: ${reducedResult.error}`);
   418→				}
   419→
   420→				this.logger.log(
   421→					`Successfully generated features for style ${style.id} using reduced fields`,
   422→				);
   423→				return reducedResult.description ?? [];
   424→			}
   425→
   426→			this.logger.error(`Failed to generate features for style ${style.id}:`, error);
   427→			throw error;
   428→		}
   429→	}
