   564→	private getDefaultUnitPrices({
   565→		style,
   566→	}: {
   567→		style: MMSStyleToProcess;
   568→	}): MMSStyleToProcess['default_unit_prices'] {
   569→		return style.default_unit_prices.reduce<MMSStyleToProcess['default_unit_prices']>(
   570→			(acc, pricesObj) => {
   571→				if (pricesObj.algorithm !== DEFAULT_PRICING_ALGORITHM) {
   572→					return acc;
   573→				}
   574→
   575→				acc.push({
   576→					quantity: pricesObj.quantity,
   577→					price: pricesObj.price,
   578→					algorithm: pricesObj.algorithm,
   579→					regular_unit_price: pricesObj.regular_unit_price ?? null,
