   717→	private extractCategoriesWithParents({
   718→		categoryIds,
   719→		allCategories,
   720→	}: {
   721→		categoryIds: number[];
   722→		allCategories: MMSAllStyleCategory[];
   723→	}): number[] {
   724→		const allCategoryIds = new Set<number>();
   725→
   726→		for (const categoryId of categoryIds) {
   727→			allCategoryIds.add(categoryId);
   728→
   729→			const parentIds = this.getAllParentCategoryIds({ categoryId, allCategories });
   730→			for (const parentId of parentIds) {
   731→				allCategoryIds.add(parentId);
   732→			}
   733→		}
   734→
   735→		return Array.from(allCategoryIds).sort((a, b) => a - b);
   736→	}
